You develop the following JavaScript code for a web resource that will be used in a model-driven app.

```
function CheckAccountRating(executionContext) {
    var formContext = executionContext.getFormContext();
    var baseUrl = Xrm.Utility.getGlobalContext();
    var id = formContext.data.entity.getId();
    var url = baseUrl + "/api/data/v9.1/accounts(" + id + ")?$select=accountingcode"

    var req = new XMLHttpRequest();
    req.open("GET", url, false);
    req.setRequestHeader("OData-MaxVersion", "4.0");
    req.setRequestHeader("OData-Version", "4.0");
    req.setRequestHeader("Accept", "application/json");
    req.setRequestHeader("Content-Type", "application/json; charset=utf-8");
    req.onreadystatechange = function () {
        if (this.readyState === 4) {
            req.onreadystatechange = null;
            if (this.status === 200) {
                var result = JSON.parse(this.response);
                if (result["accountingcode"] === 4) {
                    alert("Test");
                }
            }
        }
    };
    req.send();
}
```

